"""
Ragas evaluation for RAG pipeline quality.
Run with: pytest backend/evals/test_ragas.py -v -s
"""
import os
import pytest
from pathlib import Path
from dotenv import load_dotenv

load_dotenv()

import sys
sys.path.insert(0, str(Path(__file__).parent.parent.parent))
from backend.agent.planner import answer

RAG_EVAL_CASES = [
    {
        "question": "What is LTV?",
        "ground_truth": "LTV or Lifetime Value is the total revenue generated by a single customer across all orders.",
    },
    {
        "question": "What is the on-time delivery rate?",
        "ground_truth": "91.9% of orders are delivered on or before the estimated delivery date.",
    },
    {
        "question": "What is boleto payment?",
        "ground_truth": "Boleto is a Brazilian payment method, a bank slip paid at a bank or lottery, common for unbanked customers.",
    },
    {
        "question": "Why did orders spike in November 2017?",
        "ground_truth": "November 2017 shows a sharp spike due to Black Friday with 7544 orders vs 4631 in October.",
    },
    {
        "question": "How many customers buy more than once?",
        "ground_truth": "Only 3.12% of customers place more than one order — Olist is dominated by one-time buyers.",
    },
]


def build_dataset():
    from ragas import evaluate
    from ragas.metrics import faithfulness, answer_relevancy, context_precision
    from datasets import Dataset
    from langchain_openai import ChatOpenAI, OpenAIEmbeddings

    questions, answers, contexts, ground_truths = [], [], [], []

    for case in RAG_EVAL_CASES:
        result = answer(case["question"], history=[])
        chunks = result.get("chunks", [])
        ctx = [c["text"] for c in chunks] if chunks else ["No context retrieved"]
        ans = result.get("explanation") or (chunks[0]["text"][:300] if chunks else "No answer")

        questions.append(case["question"])
        answers.append(ans)
        contexts.append(ctx)
        ground_truths.append(case["ground_truth"])

    dataset = Dataset.from_dict({
        "question": questions,
        "answer": answers,
        "contexts": contexts,
        "ground_truth": ground_truths,
    })

    llm = ChatOpenAI(model="gpt-4o-mini", api_key=os.environ["OPENAI_API_KEY"])
    embeddings = OpenAIEmbeddings(api_key=os.environ["OPENAI_API_KEY"])

    scores = evaluate(
        dataset,
        metrics=[faithfulness, answer_relevancy, context_precision],
        llm=llm,
        embeddings=embeddings,
    ).to_pandas()

    print("\n=== RAGAS SCORES ===")
    print(scores[["question", "faithfulness", "answer_relevancy", "context_precision"]].to_string())

    Path(__file__).parent.joinpath("ragas_results.json").write_text(
        scores.to_json(orient="records", indent=2)
    )
    return scores


def test_ragas_faithfulness():
    scores = build_dataset()
    avg = scores["faithfulness"].mean()
    print(f"\nAvg faithfulness: {avg:.2f}")
    assert avg >= 0.5, f"Faithfulness too low: {avg:.2f}"


def test_ragas_relevancy():
    scores = build_dataset()
    avg = scores["answer_relevancy"].mean()
    print(f"\nAvg answer relevancy: {avg:.2f}")
    assert avg >= 0.5, f"Answer relevancy too low: {avg:.2f}"
